expect(payload).to.include({
	userId: userId.toString(),
	email: "jwt@example.com",
	role: "clerk",
});
expect(extractTokenFromHeader(`Bearer ${token}`)).to.equal(token);
expect(extractTokenFromHeader("Token abc")).to.equal(null);

